function getSumOfMSFTStockPricePreviousThreeDays() {  
    const symbol = 'MSFT';  
    const numberOfDays = 3;  
    let sumOfStockPrices = 0;  

    for (let i = 1; i <= numberOfDays; i++) {  
      const date = getDateForDaysFromToday(-i); // i days ago  
      const stockPrice = getStockPrice(symbol, date);  
      sumOfStockPrices += stockPrice;  
    }  

    return sumOfStockPrices;  
  }  

function Run() {
    return getSumOfMSFTStockPricePreviousThreeDays()
}
